<!doctype html><html><head><meta charset="utf-8"><title>Affiliate Statement</title><style>body{font-family:Arial,sans-serif;color:#111827;margin:32px}table{width:100%;border-collapse:collapse}th,td{padding:8px;border-bottom:1px solid #e5e7eb;text-align:left}.right{text-align:right}.muted{color:#64748b}.summary{display:flex;gap:12px;margin:20px 0}.box{border:1px solid #e5e7eb;padding:12px;flex:1}@media print{button{display:none}}</style></head><body>
<button onclick="window.print()">Print / Save PDF</button>
<h2>Affiliate Statement</h2><p class="muted"><?= e((string)$affiliate['full_name']) ?> | <?= e((string)$affiliate['email']) ?></p>
<div class="summary"><?php foreach ([['Opening',$statement['opening_balance']], ['Earned',$statement['earned']], ['Paid',$statement['paid']], ['Reversed',$statement['reversed']], ['Closing',$statement['closing_balance']]] as $stat): ?><div class="box"><div class="muted"><?= e($stat[0]) ?></div><strong>ZMW <?= number_format((float)$stat[1], 2) ?></strong></div><?php endforeach; ?></div>
<table><thead><tr><th>Date</th><th>Company</th><th>Invoice</th><th class="right">Payment</th><th class="right">Commission</th><th>Status</th></tr></thead><tbody><?php foreach ($statement['items'] as $item): ?><tr><td><?= e((string)$item['earned_at']) ?></td><td><?= e((string)($item['company_name'] ?? '-')) ?></td><td><?= e((string)($item['invoice_number'] ?? '-')) ?></td><td class="right"><?= number_format((float)$item['payment_amount'], 2) ?></td><td class="right"><?= number_format((float)$item['commission_amount'], 2) ?></td><td><?= e((string)$item['status']) ?></td></tr><?php endforeach; ?></tbody></table>
</body></html>
